import 'package:flutter/material.dart';
import '../services/api_service.dart';
import '../widgets/app_sidebar.dart';

class NotificationsScreen extends StatefulWidget{const NotificationsScreen({super.key});@override State<NotificationsScreen> createState()=>_State();}
class _State extends State<NotificationsScreen>{final api=ApiService();bool loading=true;String? error;List<Map<String,dynamic>> items=[];int unread=0;@override void initState(){super.initState();load();}Future<void> load()async{setState(()=>loading=true);try{final d=await api.getNotifications();items=List<Map<String,dynamic>>.from(d['notifications']??const[]);unread=(d['unread_count'] as num?)?.toInt()??0;error=null;}catch(e){error=e.toString();}if(mounted)setState(()=>loading=false);}IconData icon(String type)=>type.contains('badge')?Icons.emoji_events:type.contains('nudge')||type.contains('reminder')?Icons.notifications_active:type=='at_risk'?Icons.warning_amber:Icons.notifications;@override Widget build(BuildContext context)=>Scaffold(drawer:const AppSidebar(role:'participant'),appBar:AppBar(title:Text('Notifications${unread>0?' ($unread unread)':''}'),actions:[TextButton(onPressed:unread==0?null:()async{await api.markNotificationRead(all:true);load();},child:const Text('Mark all read')),IconButton(onPressed:load,icon:const Icon(Icons.refresh))]),body:loading?const Center(child:CircularProgressIndicator()):error!=null?Center(child:Text('Could not load notifications: $error')):items.isEmpty?const Center(child:Text('No notifications.')):ListView.builder(padding:const EdgeInsets.all(20),itemCount:items.length,itemBuilder:(c,i){final n=items[i],read=n['is_read']==true||n['is_read']==1;return Card(color:read?null:Theme.of(c).colorScheme.primaryContainer,child:ListTile(leading:CircleAvatar(child:Icon(icon(n['type']?.toString()??''))),title:Text(n['title']?.toString()??'',style:TextStyle(fontWeight:read?FontWeight.normal:FontWeight.bold)),subtitle:Text('${n['message']??''}\n${n['scheduled_at']??n['created_at']??''}'),isThreeLine:true,onTap:read?null:()async{await api.markNotificationRead(id:n['id'] as int);load();}));}));}
